#include <bits/stdc++.h>
using namespace std;

int L[100005], R[100005];

int heightOf(int x) {
    if (x == -1) return -1;
    return 1 + max(heightOf(L[x]), heightOf(R[x]));
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    for (int i = 1; i <= n; i++) { L[i] = -1; R[i] = -1; }
    for (int i = 0; i < n; i++) {
        int x, l, r; cin >> x >> l >> r;
        L[x] = l; R[x] = r;
    }
    cout << heightOf(1) << "\n";
    return 0;
}
